import Combine
import Foundation

struct DataFetcher {
    static func fetchData(from url: URL) -> AnyPublisher<Data, Error> {
        URLSession.shared.dataTask(with: url)
            .publisher
            .map { (data, response) -> Data in
                guard let response = response as? HTTPURLResponse, (200...299).contains(response.statusCode) else {
                    throw URLError(.badServerResponse)
                }
                return data
            }
            .eraseToAnyPublisher()
    }
}

// Usage
let url = URL(string: "https://jsonplaceholder.typicode.com/todos/1")!
DataFetcher.fetchData(from: url)
    .sink(receiveCompletion: {
        completion in
        switch completion {
        case .finished: print("Completed")
        case .failure(let error): print("Error: \(error)")
        }
    }, receiveValue: {
        data in
        do {
            let decodedData = try JSONDecoder().decode([String: Any].self, from: data)
            print(decodedData)
        } catch {
            print("Decoding error: \(error)")
        }
    })
    .store(in: &cancellables)

var cancellables = Set<AnyCancellable>()
```
Giải thích: `DataFetcher` sử dụng `URLSession.shared.dataTask(with:)` để tạo một data task.  `.publisher` chuyển đổi task thành một publisher.  `map` chuyển đổi response thành data, kiểm tra status code và throw error nếu cần. `eraseToAnyPublisher()` ẩn các chi tiết implementation của publisher. `sink` subscribe vào publisher và xử lý completion và value.  `store(in: &cancellables)` giữ publisher alive.

